(118, 31, 'sudah sampai yang 163', 'Uang hasil panen Rp 194.000 sudah masuk ke tabungan koperasi bapak/ibu.', '2026-07-10 17:36:16.871'),
(119, 31, 'semua pesanan sisanya jg sudah sampai', 'Bapak/Ibu punya beberapa pesanan yang sedang dikirim:\nPesanan #141: 250 kg Cabai\nPesanan #138: 100 kg Beras\n\nYang mana yang sudah sampai? (Balas dengan ID, contoh: Pesanan #45).', '2026-07-10 17:42:21.139'),
(120, 31, 'keduanya', 'Bapak/Ibu punya beberapa pesanan yang sedang dikirim:\nPesanan #141: 250 kg Cabai\nPesanan #138: 100 kg Beras\n\nYang mana yang sudah sampai? (Balas dengan ID, contoh: Pesanan #45).', '2026-07-10 17:44:26.162'),
(121, 31, 'keduanya', 'Bapak/Ibu punya beberapa pesanan yang sedang dikirim:\nPesanan #141: 250 kg Cabai\nPesanan #138: 100 kg Beras\n\nYang mana yang sudah sampai? (Mohon balas satu per satu dengan ID-nya, contoh: Pes', '2026-07-10 17:46:59.929'),
(122, 31, 'pesanan cabai', 'Pesanan belanja bapak/ibu sudah kami catat dan sedang dicarikan petani penyedianya:\n\nKami akan memberi kabar jika sudah ada petani yang siap mengirimkannya.', '2026-07-10 17:47:15.312'),
