(143, 32, 'baik', 'Pesanan sudah bapak/ibu kunci. Silakan siapkan barangnya untuk dikirim ya Pak/Bu.', '2026-07-11 01:23:40.692'),
(144, 32, 'barangnya sudah saya kirim ya', 'Bapak/Ibu punya beberapa pesanan aktif yang siap dikirim:\n[162] 15 kg BERAS\n[188] 20 kg BERAS\n[185] 15 kg BERAS\n[187] 20 kg BERAS\n\nYang mana yang mulai dikirim? (Balas dengan angkanya saja, c', '2026-07-11 01:23:54.059'),
(145, 32, '188', 'Hanya Admin SPPG atau Juri yang berhak menyelesaikan pesanan.', '2026-07-11 01:24:32.107'),
(146, 31, 'saya mau beli dari dia', 'Nggih Pak, maksudnya ingin beli komoditas apa dan berapa jumlahnya nggih? Mohon disebutkan supaya bisa segera saya carikan petani penyedianya.', '2026-07-11 01:25:11.015'),
(147, 31, 'beras 20 kg', 'Pesanan belanja bapak/ibu sudah kami catat dan sedang dicarikan petani penyedianya:\n1. 20 kg Beras\n\nKami akan memberi kabar jika sudah ada petani yang siap mengirimkannya.', '2026-07-11 01:25:29.288'),
(148, 32, 'pesanan sudah kirim', 'Nggih Pak Surya, untuk pesanan yang sudah dikirim, mohon ditunggu sebentar ya Pak. Nanti bagian Admin SPPG atau Juri kami yang akan memproses dan menyelesaikan status pesanannya kalau sudah d', '2026-07-11 01:26:24.121'),
(149, 31, 'apakah sudah dikirim', 'Sabar dulu nggih Pak, saat ini pesanan 20 kg berasnya masih kami carikan petani penyedianya. Nanti kalau sudah ada yang siap kirim, langsung saya kabari bapak.', '2026-07-11 01:26:56.257');
